package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.BijdragePercentagesFactoryImp;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.dmfa.WerkbonusKomtInAanmerkingDmfa;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.dmfappl.WerkbonusKomtInAanmerkingDmfappl;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.rszppo.WerkbonusKomtInAanmerkingRszppo;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentagesFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmTijdperk;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import be.schaubroeck.lpb.tools.service.RegimeRszppoService;

public class WerkbonusKomtInAanmerkingFactory {

    private WerkbonusKomtInAanmerkingFactory() {

    }

    public static WerkbonusKomtInAanmerking create(BijdragePercentagesFactory bijdragePercentagesFactory, NlpGlobalService globalService, RkmTijdperk tijdperk) {
        RegimeRszppoService regimeRszppoService = globalService.getRegimeRszppoService();
        DmfapplBasisBijdrageService basisBijdrageService = globalService.getDmfapplBasisBijdrageService();
        return switch (tijdperk) {
            case RSZPPO -> new WerkbonusKomtInAanmerkingRszppo(bijdragePercentagesFactory, regimeRszppoService, basisBijdrageService);
            case DMFAPPL -> new WerkbonusKomtInAanmerkingDmfappl(bijdragePercentagesFactory, regimeRszppoService, basisBijdrageService);
            default -> new WerkbonusKomtInAanmerkingDmfa(bijdragePercentagesFactory, regimeRszppoService, basisBijdrageService);
        };
    }

    public static WerkbonusKomtInAanmerking create(RekenTijd rekenTijd, ConstantManager constantManager, NlpGlobalService globalService) {
        BijdragePercentagesFactory bijdragePercentagesFactory = new BijdragePercentagesFactoryImp(constantManager, globalService);
        return create(bijdragePercentagesFactory, globalService, RkmTijdperk.getTijdperk(rekenTijd));
    }
}
